<?php declare(strict_types=1);
namespace VeloCMS\Cli;

use VeloCMS\Core\Application;
use VeloCMS\Core\Migrator;

class MigrateCommand
{
    public function __construct(private readonly Application $app) {}

    public function run(array $args): int
    {
        $migrator = $this->app->make(Migrator::class);
        $base     = $this->app->basePath('migrations');

        echo "Running migrations...\n";

        // Core migrations (velocms_core database)
        $coreRan = $migrator->run($base . '/core');
        if (empty($coreRan)) {
            echo "  [core] Nothing to migrate.\n";
        } else {
            foreach ($coreRan as $file) {
                echo "  [core] ✓ {$file}\n";
            }
        }

        // Module migrations in migrations/{module}/ directories
        foreach (glob($base . '/*/') ?: [] as $modPath) {
            $module = basename(rtrim($modPath, '/'));
            if ($module === 'core') continue;
            $modRan = $migrator->run($modPath);
            if (empty($modRan)) {
                echo "  [{$module}] Nothing to migrate.\n";
            } else {
                foreach ($modRan as $file) {
                    echo "  [{$module}] ✓ {$file}\n";
                }
            }
        }

        // Module migrations inside modules/{name}/migrations/ (legacy location)
        $modulesPath = $this->app->basePath('modules');
        foreach (glob($modulesPath . '/*/migrations') ?: [] as $modPath) {
            $module  = basename(dirname($modPath));
            $modRan  = $migrator->run($modPath);
            foreach ($modRan as $file) {
                echo "  [{$module}/internal] ✓ {$file}\n";
            }
        }

        echo "Done.\n";
        return 0;
    }
}

