'use strict';

(function () {
    const sidebar  = document.querySelector('.vcms-sidebar');
    const overlay  = document.querySelector('.vcms-overlay');
    const hamburger = document.querySelector('.vcms-hamburger');

    if (!sidebar || !hamburger) return;

    function openNav() {
        sidebar.classList.add('open');
        overlay.classList.add('active');
        document.body.classList.add('vcms-nav-open');
        hamburger.setAttribute('aria-expanded', 'true');
    }

    function closeNav() {
        sidebar.classList.remove('open');
        overlay.classList.remove('active');
        document.body.classList.remove('vcms-nav-open');
        hamburger.setAttribute('aria-expanded', 'false');
    }

    hamburger.addEventListener('click', function () {
        sidebar.classList.contains('open') ? closeNav() : openNav();
    });

    overlay.addEventListener('click', closeNav);

    // Close sidebar when a nav link is clicked on mobile
    sidebar.querySelectorAll('.vcms-nav a').forEach(function (link) {
        link.addEventListener('click', function () {
            if (window.innerWidth < 768) closeNav();
        });
    });

    // Close on Escape
    document.addEventListener('keydown', function (e) {
        if (e.key === 'Escape') closeNav();
    });

    // Reset on resize to desktop
    window.addEventListener('resize', function () {
        if (window.innerWidth >= 768) closeNav();
    });
}());

