    /* Hide name + role badge on mobile to save space */
    .vcms-topbar-user > span:first-of-type,
    .vcms-role-badge { display: none; }

    /* Content */
    .vcms-content { padding: 14px; }

    /* Cards: 2-column on mobile, 1-column on very small */
    .vcms-cards-grid { grid-template-columns: repeat(2, 1fr); gap: 10px; }
    .vcms-card { padding: 14px; }
    .vcms-card .value { font-size: 26px; }

    /* form-row: stack vertically */
    .vcms-form-row { flex-direction: column; gap: 0; }
    .vcms-form-row .vcms-form-group { min-width: 0; }

    /* form-table: convert to label-above-input layout */
    .vcms-table--form,
    .vcms-table--form tbody,
    .vcms-table--form tr { display: block; }
    .vcms-table--form th {
        display: block;
        width: 100%;
        padding: 0.75rem 0 0.25rem;
        border-bottom: none;
    }
    .vcms-table--form td {
        display: block;
        padding: 0 0 0.75rem;
    }

    /* Page header: allow wrapping */
    .vcms-page-header { gap: 8px; }
    .vcms-page-header a,
    .vcms-page-header button { margin-left: 0; }

    /* Filter bar: full width input */
    .vcms-filter-bar input { max-width: 100%; }

    /* Slug prefix: hide long URLs, show just "/" */
    .vcms-slug-prefix { display: none; }

    /* Editor: smaller min-height */
    .vcms-editor { min-height: 180px; }

    /* Form actions: stack on very small */
    .vcms-form-actions { flex-direction: column; align-items: stretch; }
    .vcms-form-actions .vcms-btn,
    .vcms-form-actions a { text-align: center; }

    /* Tabs: scrollable */
    .vcms-tabs { gap: 0; }

    /* Cards grid: 1 column on very small phones */
    @media (max-width: 400px) {
        .vcms-cards-grid { grid-template-columns: 1fr; }
    }
}

/* Booking status badges */
.vcms-badge--pending   { background: #fef3c7; color: #92400e; }
.vcms-badge--confirmed { background: #d1fae5; color: #065f46; }
.vcms-badge--cancelled { background: #f3f4f6; color: #6b7280; }

/* ── Session 10 additions ── */

/* Autosave banner */
.vcms-autosave-banner { font-size:.82rem; padding:.3rem .75rem; border-radius:4px; margin-bottom:.75rem; min-height:1.6rem; transition:opacity .3s; }
.vcms-autosave-banner--ok  { background:#dcfce7; color:#15803d; }
.vcms-autosave-banner--error { background:#fee2e2; color:#b91c1c; }

/* Collapsible section header */
.vcms-section-header { display:flex; align-items:center; justify-content:space-between; margin-bottom:.75rem; }
.vcms-section-header h4 { margin:0; }
.vcms-section-body { overflow:hidden; max-height:4000px; opacity:1; transition:max-height .35s ease, opacity .25s; }
.vcms-section-body.vcms-collapsed { max-height:0 !important; opacity:0; pointer-events:none; }

/* Business hours day grid */
.bh-days-grid { display:flex; flex-direction:column; gap:.1rem; padding:.25rem 0; }
.bh-day-row { display:flex; align-items:center; gap:.85rem; padding:.4rem .25rem; border-bottom:1px solid #f3f4f6; }
.bh-day-row:last-child { border-bottom:none; }
.bh-day-label { width:38px; font-size:.875rem; font-weight:500; color:#374151; flex-shrink:0; }
.bh-day-times { display:flex; align-items:center; gap:.5rem; font-size:.875rem; }
.bh-day-times input[type="time"] { width:108px; padding:.28rem .5rem; font-size:.875rem; }
.bh-day-times.bh-hidden { visibility:hidden; pointer-events:none; }

/* Inline package / product cards */
.vcms-inline-card { margin-top:1rem; padding:1rem 1.1rem; background:#f8fafc; border:1px solid #e5e7eb; border-radius:6px; }
.vcms-inline-card h5 { margin:0 0 .65rem; font-size:.88rem; color:#374151; font-weight:600; }
.vcms-inline-table { width:100%; border-collapse:collapse; font-size:.84rem; }
.vcms-inline-table th { background:#f1f5f9; font-weight:600; padding:.35rem .55rem; text-align:left; border-bottom:1px solid #e5e7eb; }
.vcms-inline-table td { padding:.35rem .55rem; vertical-align:middle; }
.vcms-inline-table tr + tr td { border-top:1px solid #f1f5f9; }
.vcms-inline-add-row { display:flex; gap:.5rem; flex-wrap:wrap; margin-top:.75rem; align-items:flex-end; }
.vcms-inline-add-row input, .vcms-inline-add-row select { min-width:0; width:auto; flex:1 1 120px; }
.vcms-inline-add-row .vcms-btn { flex-shrink:0; }

/* Slot row toggle */
#bk-slot-row { padding:.25rem 0 .25rem 3.6rem; display:flex; align-items:center; gap:.5rem; flex-wrap:wrap; font-size:.875rem; }
#bk-slot-row select { width:auto; min-width:160px; }

