#!/usr/bin/env python3
"""VeloCMS Translation System — Full deployment script (Session 16)"""

import os, json, subprocess

BASE = '/var/www/velocms'

def write(rel, content):
    full = os.path.join(BASE, rel)
    os.makedirs(os.path.dirname(full), exist_ok=True)
    with open(full, 'w', encoding='utf-8') as f:
        f.write(content)
    print(f'  wrote  {rel}')

def append(rel, content):
    full = os.path.join(BASE, rel)
    with open(full, 'a', encoding='utf-8') as f:
        f.write(content)
    print(f'  appended {rel}')

def read(rel):
    with open(os.path.join(BASE, rel), encoding='utf-8') as f:
        return f.read()

def patch(rel, old, new):
    content = read(rel)
    if old not in content:
        print(f'  WARN  patch target not found in {rel}')
        return
    write(rel, content.replace(old, new, 1))
    print(f'  patched {rel}')

# ─────────────────────────────────────────────────────────────────────────────
print('\n=== 1. Migration ===')
# ─────────────────────────────────────────────────────────────────────────────
write('migrations/i18n/001_create_translations_table.php', r"""<?php declare(strict_types=1);
return new class {
    public function up(\PDO $pdo): void
    {
        $pdo->exec("CREATE TABLE IF NOT EXISTS translations (
            id              BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,
            lang            VARCHAR(10)  NOT NULL,
            trans_key       VARCHAR(255) NOT NULL,
            value           TEXT         NOT NULL,
            auto_translated TINYINT(1)   NOT NULL DEFAULT 0,
            created_at      DATETIME     NOT NULL DEFAULT CURRENT_TIMESTAMP,
            updated_at      DATETIME     NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
            UNIQUE KEY uq_lang_key (lang, trans_key),
            KEY idx_lang (lang)
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci");

        $defaults = [
            ['de','nav.dashboard','Übersicht'],    ['en','nav.dashboard','Dashboard'],
            ['de','nav.booking','Buchungen'],       ['en','nav.booking','Booking'],
            ['de','nav.pages','Seiten'],            ['en','nav.pages','Pages'],
            ['de','nav.blog','Blog'],               ['en','nav.blog','Blog'],
            ['de','nav.media','Medien'],            ['en','nav.media','Media'],
            ['de','nav.navigation','Navigation'],   ['en','nav.navigation','Navigation'],
            ['de','nav.seo','SEO'],                 ['en','nav.seo','SEO'],
            ['de','nav.forms','Formulare'],         ['en','nav.forms','Forms'],
            ['de','nav.sites','Websites'],          ['en','nav.sites','Sites'],
            ['de','nav.users','Benutzer'],          ['en','nav.users','Users'],
            ['de','nav.api_keys','API-Schlüssel'],  ['en','nav.api_keys','API Keys'],
            ['de','nav.audit_log','Audit-Protokoll'],['en','nav.audit_log','Audit Log'],
            ['de','nav.cron_jobs','Cron-Jobs'],     ['en','nav.cron_jobs','Cron Jobs'],
            ['de','nav.settings','Einstellungen'],  ['en','nav.settings','Settings'],
            ['de','nav.translations','Übersetzungen'],['en','nav.translations','Translations'],
            ['de','nav.profile','Profil'],           ['en','nav.profile','Profile'],
            ['de','nav.signout','Abmelden'],         ['en','nav.signout','Sign out'],
            ['de','nav.content','Inhalt'],           ['en','nav.content','Content'],
            ['de','nav.system','System'],            ['en','nav.system','System'],
        ];
        $stmt = $pdo->prepare(
            'INSERT IGNORE INTO translations (lang, trans_key, value) VALUES (?, ?, ?)'
        );
        foreach ($defaults as [$lang, $key, $val]) {
            $stmt->execute([$lang, $key, $val]);
        }
    }

    public function down(\PDO $pdo): void
    {
        $pdo->exec('DROP TABLE IF EXISTS translations');
    }
};
""")

# ─────────────────────────────────────────────────────────────────────────────
print('\n=== 2. core/I18n.php ===')
# ─────────────────────────────────────────────────────────────────────────────
write('core/I18n.php', r"""<?php declare(strict_types=1);
namespace VeloCMS\Core;

class I18n
{
    private string $lang   = 'de';
    private array  $data   = [];
    private bool   $loaded = false;

    public function __construct(private readonly \PDO $pdo)
    {
        $lang = $_COOKIE['vcms_lang'] ?? 'de';
        $this->lang = in_array($lang, ['de', 'en'], true) ? $lang : 'de';
    }

    public function getLang(): string { return $this->lang; }

    public function t(string $key, array $replace = []): string
    {
        $this->load();
        $value = $this->data[$this->lang][$key]
              ?? $this->data['de'][$key]
              ?? $key;
        foreach ($replace as $k => $v) {
            $value = str_replace(':' . $k, (string) $v, $value);
        }
        return $value;
    }

    public function all(): array
    {
        $this->load();
        return $this->data;
    }

    public function forLang(string $lang): array
    {
        $this->load();
        return $this->data[$lang] ?? [];
    }

    private function load(): void
    {
        if ($this->loaded) return;
        $this->loaded = true;
        try {
            $rows = $this->pdo
                ->query('SELECT lang, trans_key, value FROM translations ORDER BY lang, trans_key')
                ->fetchAll(\PDO::FETCH_ASSOC);
            foreach ($rows as $r) {
                $this->data[$r['lang']][$r['trans_key']] = $r['value'];
            }
        } catch (\Throwable) {}
    }
}
""")

