.i18n-badge--manual{background:#d1fae5;color:#065f46}
.i18n-badge--pending{background:#f3f4f6;color:#6b7280}
.i18n-badge--ok{background:#d1fae5;color:#065f46}
</style>

<script>
const I18N_CSRF = <?= json_encode($csrf, JSON_HEX_TAG | JSON_HEX_AMP) ?>;

// Inline click-to-edit via event delegation
document.querySelector('#i18n-table tbody')?.addEventListener('click', function (ev) {
    const span = ev.target.closest('.i18n-editable');
    if (!span || span.querySelector('input')) return;

    const key  = span.dataset.key;
    const lang = span.dataset.lang;
    const orig = span.textContent.trim();

    const inp = document.createElement('input');
    inp.value = orig;
    inp.style.cssText = 'width:100%;padding:.25rem .4rem;border:1.5px solid #6366f1;border-radius:3px;font-size:.875rem;font-family:inherit;box-sizing:border-box';
    span.textContent = '';
    span.appendChild(inp);
    inp.focus(); inp.select();

    const commit = () => {
        const val = inp.value.trim();
        if (val === orig) { span.textContent = orig || '—'; return; }
        fetch('/admin/translations/update', {
            method: 'POST',
            headers: {'Content-Type':'application/x-www-form-urlencoded','X-Requested-With':'XMLHttpRequest'},
            body: new URLSearchParams({_csrf: I18N_CSRF, key, lang, value: val})
        }).then(r => r.json()).then(d => {
            span.textContent = d.ok ? (val || '—') : (orig || '—');
            if (d.ok && lang === 'en') {
                // Show manual badge
                const statusTd = span.closest('tr').querySelector('.i18n-status-cell');
                if (statusTd) statusTd.innerHTML = '<span class="i18n-badge i18n-badge--manual" title="Manual override">🔒</span>';
                span.classList.add('i18n-editable--manual');
            }
        }).catch(() => { span.textContent = orig || '—'; });
    };
    inp.addEventListener('blur', commit);
    inp.addEventListener('keydown', e => {
        if (e.key === 'Enter') { e.preventDefault(); commit(); }
        if (e.key === 'Escape') { span.textContent = orig || '—'; }
    });
});

// Per-row auto-translate via event delegation
document.querySelector('#i18n-table tbody')?.addEventListener('click', function (ev) {
    const btn = ev.target.closest('.i18n-auto-btn');
    if (!btn) return;
    const key = btn.dataset.key;
    const de  = btn.dataset.de;
    if (!de) { alert('German text missing.'); return; }
    btn.disabled = true; btn.textContent = '…';
    fetch('/admin/translations/translate', {
        method: 'POST',
        headers: {'Content-Type':'application/x-www-form-urlencoded','X-Requested-With':'XMLHttpRequest'},
        body: new URLSearchParams({_csrf: I18N_CSRF, key, text: de, lang: 'en'})
    }).then(r => r.json()).then(d => {
        if (d.ok) {
            const td = btn.closest('td');
            td.innerHTML = '<span class="i18n-editable" data-key="' + escH(key) + '" data-lang="en" title="Auto-translated — click to edit">' + escH(d.translation) + '</span>';
            const s = btn.closest('tr').querySelector('.i18n-status-cell');
            if (s) s.innerHTML = '<span class="i18n-badge i18n-badge--auto">auto</span>';
        } else {
            btn.disabled = false; btn.textContent = '✦ Auto';
            alert(d.error || 'Translation failed. Check API key in settings.');
        }
    }).catch(() => { btn.disabled = false; btn.textContent = '✦ Auto'; });
});

function escH(s) {
    return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

// Re-translate all auto entries
document.getElementById('btn-retranslate')?.addEventListener('click', function () {
    if (!confirm('Re-translate all auto-translated English entries?\n\nManual overrides (🔒) will be skipped.')) return;
    this.disabled = true; this.textContent = 'Translating…';
    const btn = this;
    fetch('/admin/translations/retranslate-auto', {
        method: 'POST',
        headers: {'Content-Type':'application/x-www-form-urlencoded','X-Requested-With':'XMLHttpRequest'},
        body: new URLSearchParams({_csrf: I18N_CSRF})
    }).then(r => r.json()).then(d => {
        btn.disabled = false; btn.textContent = 'Re-translate all auto entries';
        if (d.ok) {
            alert('Done!\nTranslated: ' + d.translated + '\nSkipped (manual 🔒): ' + d.skipped + '\nErrors: ' + d.errors);
            if (d.translated > 0) location.reload();
        } else {
            alert('Failed. Check API key in settings above.');
        }
    }).catch(() => { btn.disabled = false; btn.textContent = 'Re-translate all auto entries'; });
});
</script>
""")

