(function () {
    const COOKIE = 'vcms_lang';
    const LANGS  = ['de', 'en'];

    function applyLang(lang) {
        const dict = ((window.__VCMS_I18N__ || {})[lang]) || {};
        document.querySelectorAll('[data-i18n]').forEach(function (el) {
            const v = dict[el.dataset.i18n];
            if (v !== undefined) el.textContent = v;
        });
        document.querySelectorAll('[data-i18n-placeholder]').forEach(function (el) {
            const v = dict[el.dataset.i18nPlaceholder];
            if (v !== undefined) el.placeholder = v;
        });
        document.querySelectorAll('[data-lang-toggle]').forEach(function (btn) {
            btn.classList.toggle('active', btn.dataset.lang === lang);
        });
        window.__VCMS_LANG__ = lang;
    }

    function setLang(lang) {
        if (!LANGS.includes(lang)) return;
        document.cookie = COOKIE + '=' + lang + ';path=/;max-age=31536000;SameSite=Lax';
        try { localStorage.setItem(COOKIE, lang); } catch (_) {}
        applyLang(lang);
    }

    // Deferred — DOM already parsed when this runs
    applyLang(window.__VCMS_LANG__ || 'de');

    document.querySelectorAll('[data-lang-toggle]').forEach(function (btn) {
        btn.addEventListener('click', function () { setLang(btn.dataset.lang); });
