#!/usr/bin/env python3
"""
i18n fix: Option B (reload) + simplified Translations admin + pending-only translation.

Changes:
1. public/assets/i18n.js         — setLang() now reloads the page
2. public/assets/admin/i18n.js   — same
3. modules/i18n/models/Translation.php  — add getPending(), countPending(), countByLang()
4. modules/i18n/admin/controllers/I18nAdminController.php — counts in index(), use getPending() in retranslateAll()
5. admin/views/i18n/index.php    — remove monitoring table, show counter + "Translate all pending"
"""
import os

BASE = '/var/www/velocms'

def write(rel, content):
    path = os.path.join(BASE, rel)
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, 'w', encoding='utf-8') as f:
        f.write(content)
    print(f'  wrote  {rel}')

# ── 1. public/assets/i18n.js ─────────────────────────────────────────────────
write('public/assets/i18n.js', r"""'use strict';
/* VeloCMS i18n — language selection via cookie + page reload */
(function () {
    const COOKIE = 'vcms_lang';
    const LANGS  = ['de', 'en'];

    function markActive(lang) {
        document.querySelectorAll('[data-lang-toggle]').forEach(function (btn) {
            const active = btn.dataset.lang === lang;
            btn.classList.toggle('active', active);
            btn.setAttribute('aria-pressed', active ? 'true' : 'false');
        });
        window.__VCMS_LANG__ = lang;
    }

    function setLang(lang) {
        if (!LANGS.includes(lang)) return;
        document.cookie = COOKIE + '=' + lang + ';path=/;max-age=31536000;SameSite=Lax';
        try { localStorage.setItem(COOKIE, lang); } catch (_) {}
        location.reload();
    }

    // Mark the currently active language button on page load
    markActive(window.__VCMS_LANG__ || 'de');

    document.querySelectorAll('[data-lang-toggle]').forEach(function (btn) {
        btn.addEventListener('click', function () { setLang(btn.dataset.lang); });
    });

    window.vcmsI18n = { setLang: setLang };
    // window.t() — client-side translation lookup (for JS that renders strings)
    window.t = function (key) {
        const lang = window.__VCMS_LANG__ || 'de';
        return (((window.__VCMS_I18N__ || {})[lang]) || {})[key] || key;
    };
}());
""")

# ── 2. public/assets/admin/i18n.js ───────────────────────────────────────────
write('public/assets/admin/i18n.js', r"""'use strict';
/* VeloCMS admin i18n — language selection via cookie + page reload */
(function () {
    const COOKIE = 'vcms_lang';
    const LANGS  = ['de', 'en'];

    function markActive(lang) {
        document.querySelectorAll('[data-lang-toggle]').forEach(function (btn) {
            const active = btn.dataset.lang === lang;
            btn.classList.toggle('active', active);
            btn.setAttribute('aria-pressed', active ? 'true' : 'false');
        });
        window.__VCMS_LANG__ = lang;
    }

    function setLang(lang) {
        if (!LANGS.includes(lang)) return;
        document.cookie = COOKIE + '=' + lang + ';path=/;max-age=31536000;SameSite=Lax';
        try { localStorage.setItem(COOKIE, lang); } catch (_) {}
        location.reload();
    }

    markActive(window.__VCMS_LANG__ || 'de');

    document.querySelectorAll('[data-lang-toggle]').forEach(function (btn) {
        btn.addEventListener('click', function () { setLang(btn.dataset.lang); });
    });

    window.vcmsI18n = { setLang: setLang };
    window.t = function (key) {
        const lang = window.__VCMS_LANG__ || 'de';
        return (((window.__VCMS_I18N__ || {})[lang]) || {})[key] || key;
    };
}());
""")

# ── 3. modules/i18n/models/Translation.php ───────────────────────────────────
write('modules/i18n/models/Translation.php', r"""<?php declare(strict_types=1);
namespace VeloCMS\Modules\I18n\Models;

class Translation
{
    public function __construct(private readonly \PDO $pdo) {}

    /** Insert or update a translation. Does NOT change manual_override on existing rows. */
    public function set(string $lang, string $key, string $value, bool $auto = false): void
    {
        $this->pdo->prepare(
            'INSERT INTO translations (lang, trans_key, value, auto_translated, manual_override)
             VALUES (?, ?, ?, ?, 0)
             ON DUPLICATE KEY UPDATE value = VALUES(value),
             auto_translated = VALUES(auto_translated), updated_at = NOW()'
        )->execute([$lang, $key, $value, $auto ? 1 : 0]);
    }

    /** Mark a translation as manually overridden — never re-translated by auto. */
    public function setWithManualOverride(string $lang, string $key, string $value): void
    {
        $this->pdo->prepare(
            'INSERT INTO translations (lang, trans_key, value, auto_translated, manual_override)
             VALUES (?, ?, ?, 0, 1)
             ON DUPLICATE KEY UPDATE value = VALUES(value),
             auto_translated = 0, manual_override = 1, updated_at = NOW()'
        )->execute([$lang, $key, $value]);
    }

    /** Delete all language entries for a key. */
    public function deleteByKey(string $key): void
    {
        $this->pdo->prepare('DELETE FROM translations WHERE trans_key = ?')->execute([$key]);
    }

    /**
     * Return DE keys that have NO entry at all for $lang (truly pending).
     */
    public function getPending(string $lang): array
    {
        $stmt = $this->pdo->prepare(
            'SELECT d.trans_key, d.value AS de_value
             FROM translations d
             WHERE d.lang = "de"
               AND NOT EXISTS (
                   SELECT 1 FROM translations e
                   WHERE e.lang = ? AND e.trans_key = d.trans_key
               )
             ORDER BY d.trans_key'
        );
        $stmt->execute([$lang]);
        return $stmt->fetchAll(\PDO::FETCH_ASSOC);
    }

    /** Count pending keys: DE exists but $lang does not. */
    public function countPending(string $lang): int
    {
        $stmt = $this->pdo->prepare(
            'SELECT COUNT(*) FROM translations d WHERE d.lang = "de"
              AND NOT EXISTS (
                  SELECT 1 FROM translations e WHERE e.lang = ? AND e.trans_key = d.trans_key
              )'
        );
        $stmt->execute([$lang]);
        return (int) $stmt->fetchColumn();
    }

    /** Count all translations for a given language. */
    public function countByLang(string $lang): int
    {
        $stmt = $this->pdo->prepare('SELECT COUNT(*) FROM translations WHERE lang = ?');
        $stmt->execute([$lang]);
        return (int) $stmt->fetchColumn();
    }

    /**
     * Return DE keys that can be auto-translated to $lang:
     * those without ANY manual_override $lang entry.
     * Used by retranslateAll (refresh auto entries).
     */
    public function getAutoTranslateable(string $lang): array
    {
        $stmt = $this->pdo->prepare(
            'SELECT d.trans_key, d.value AS de_value
             FROM translations d
             WHERE d.lang = "de"
             AND d.trans_key NOT IN (
                 SELECT trans_key FROM translations
                 WHERE lang = ? AND manual_override = 1
             )
             ORDER BY d.trans_key'
        );
        $stmt->execute([$lang]);
        return $stmt->fetchAll(\PDO::FETCH_ASSOC);
    }

    /** Count manual override entries for a language. */
    public function countManualOverrides(string $lang): int
    {
        $stmt = $this->pdo->prepare(
            'SELECT COUNT(*) FROM translations WHERE lang = ? AND manual_override = 1'
        );
        $stmt->execute([$lang]);
        return (int) $stmt->fetchColumn();
    }
}
