# ── HTTP → HTTPS (both www and non-www) ──────────────────────────────────────
server {
    listen 80;
    listen [::]:80;
    server_name webzite-newmedia.com www.webzite-newmedia.com;
    return 301 https://webzite-newmedia.com$request_uri;
}

# ── www HTTPS → non-www redirect ─────────────────────────────────────────────
server {
    listen 443 ssl;
    listen [::]:443 ssl;
    server_name www.webzite-newmedia.com;

    ssl_certificate     /etc/letsencrypt/live/webzite-newmedia.com/fullchain.pem;
    ssl_certificate_key /etc/letsencrypt/live/webzite-newmedia.com/privkey.pem;
    include             /etc/letsencrypt/options-ssl-nginx.conf;
    ssl_dhparam         /etc/letsencrypt/ssl-dhparams.pem;

    return 301 https://webzite-newmedia.com$request_uri;
}

# ── FastCGI cache zone (defined in http context via conf.d snippet) ───────────
# Declared in /etc/nginx/conf.d/velocms_cache_zone.conf

# ── Main HTTPS site ───────────────────────────────────────────────────────────
server {
    listen 443 ssl;
    listen [::]:443 ssl ipv6only=on;
    server_name webzite-newmedia.com;

    root  /var/www/velocms/public;
    index index.php;

    ssl_certificate     /etc/letsencrypt/live/webzite-newmedia.com/fullchain.pem;
    ssl_certificate_key /etc/letsencrypt/live/webzite-newmedia.com/privkey.pem;
    include             /etc/letsencrypt/options-ssl-nginx.conf;
    ssl_dhparam         /etc/letsencrypt/ssl-dhparams.pem;

    add_header Strict-Transport-Security "max-age=31536000; includeSubDomains" always;
    add_header X-Frame-Options "SAMEORIGIN" always;
    add_header X-Content-Type-Options "nosniff" always;
    add_header Referrer-Policy "strict-origin-when-cross-origin" always;
    add_header X-Cache-Status $upstream_cache_status always;

    # Static assets — long TTL, immutable
    location /assets/ {
        expires 1y;
        add_header Cache-Control "public, immutable";
    }

    location /storage/uploads/ {
        expires 7d;
        add_header Cache-Control "public";
    }

    # Block direct access to storage root (logs, cache, backups)
    location /storage/ {
        deny all;
        return 403;
    }

    location / {
        try_files $uri $uri/ /index.php?$query_string;
    }

    location ~ \.php$ {
        fastcgi_pass  unix:/run/php/php8.5-fpm.sock;
        fastcgi_param SCRIPT_FILENAME $realpath_root$fastcgi_script_name;
        fastcgi_param HTTP_HOST $host;
        include       fastcgi_params;

        # FastCGI cache
        fastcgi_cache           velocms_cache;
        fastcgi_cache_valid      200 301 302 10m;
        fastcgi_cache_valid      404 1m;
        fastcgi_cache_use_stale  error timeout updating http_500 http_503;
        fastcgi_cache_lock       on;
        fastcgi_cache_min_uses   1;

        # Bypass cache for logged-in users and POST requests
        fastcgi_cache_bypass $no_cache;
        fastcgi_no_cache     $no_cache;
    }

    location ~ /\. {
        deny all;
    }
}

