# FastCGI cache zone for VeloCMS
fastcgi_cache_path /var/cache/nginx/velocms
    levels=1:2
    keys_zone=velocms_cache:10m
    max_size=256m
    inactive=30m
    use_temp_path=off;

fastcgi_cache_key "$scheme$request_method$host$request_uri";

# Skip cache for POST requests
map $request_method $no_cache_method {
    default 0;
    POST    1;
}

# Skip cache for logged-in users
map $http_cookie $no_cache_cookie {
    default              0;
    "~*velocms_session" 1;
    "~*velocms_admin"   1;
}

# Skip cache for admin paths
map $request_uri $no_cache_admin {
    default  0;
    "~/admin" 1;
    "~/api"   1;
}

map "$no_cache_method$no_cache_cookie$no_cache_admin" $no_cache {
    "~1" 1;
    default 0;
}

