// Global error handler — logs errors, shows safe message in production
set_error_handler(static function (int $errno, string $errstr, string $errfile, int $errline) use ($app): bool {
    try { $app->make(Logger::class)->error("PHP [{$errno}] {$errstr}", ['file' => $errfile, 'line' => $errline]); }
    catch (\Throwable) {}
    return true;
});

set_exception_handler(static function (\Throwable $e) use ($app): never {
    try { $app->make(Logger::class)->error($e->getMessage(), ['file' => $e->getFile(), 'line' => $e->getLine(), 'trace' => $e->getTraceAsString()]); }
    catch (\Throwable) {}
    http_response_code(500);
    $debug = $app->make(Config::class)->get('APP_DEBUG', 'false') === 'true';
    echo $debug
        ? '<pre>' . htmlspecialchars((string) $e) . '</pre>'
        : '<h1>500 &mdash; Server Error</h1><p>Something went wrong. Please try again later.</p>';
    exit(1);
});

return $app;

